	public void addStatement(Statement st) {
		Objects.requireNonNull(st);
		if (!rebuildRequired.get() && !sketchesLoaded && persistenceEnabled && persistenceFile != null
				&& hasSnapshotAvailable(persistenceFile)) {
			tryLoadFromDisk();
		}
		if (!sketchesLoaded) {
			approxStoreSize.incrementAndGet();
			rebuildRequired.set(true);
			return;
		}

		String s = str(st.getSubject());
		String p = str(st.getPredicate());
		String o = str(st.getObject());
		String c = str(st.getContext());
		String signature = sig(s, p, o, c);
		churnSampler.recordAdd(signature, samplingInterval());
		seenTriples = approxStoreSize.incrementAndGet();

		try {
			ingestIncremental(s, p, o, c, false);

//				while (true) {
//					long epoch = rebuildEpoch.get();
//					if ((epoch & 1L) != 0L) {
//						synchronized (bufA) {
//							ingest(bufA, st, false);
//						}
//						synchronized (bufB) {
//							ingest(bufB, st, false);
//						}
//						break;
//					}
//
//					State target = current;
//					synchronized (target) {
//						if (rebuildEpoch.get() != epoch) {
//							continue;
//						}
//						ingest(target, st, false);
//						break;
//					}
//				}

		} catch (MemoryPressureAbort | OutOfMemoryError oom) {
			logger.warn("Out of memory while applying incremental estimator update; unloading sketches", oom);
			unloadInternal(true);
			return;
		}
		dirty.set(true);
	}

	public void addStatement(Resource s, IRI p, Value o, Resource c) {
		addStatement(sailStore.getValueFactory().createStatement(s, p, o, c));
	}

	public void addStatement(Resource s, IRI p, Value o) {
		addStatement(s, p, o, null);
	}

	public void deleteStatement(Statement st) {
		Objects.requireNonNull(st);
		if (!rebuildRequired.get() && !sketchesLoaded && persistenceEnabled && persistenceFile != null
				&& hasSnapshotAvailable(persistenceFile)) {
			tryLoadFromDisk();
		}
		if (!sketchesLoaded) {
			approxStoreSize.updateAndGet(v -> Math.max(0, v - 1));
			rebuildRequired.set(true);
			return;
		}

		String s = str(st.getSubject());
		String p = str(st.getPredicate());
		String o = str(st.getObject());
		String c = str(st.getContext());
		String signature = sig(s, p, o, c);
		churnSampler.recordDelete(signature, samplingInterval());
		seenTriples = approxStoreSize.updateAndGet(v -> Math.max(0, v - 1));

		try {
			ingestIncremental(s, p, o, c, true);
		} catch (MemoryPressureAbort | OutOfMemoryError oom) {
			logger.warn("Out of memory while applying incremental estimator delete; unloading sketches", oom);
			unloadInternal(true);
			return;
		}
		dirty.set(true);
	}

	public void deleteStatement(Resource s, IRI p, Value o, Resource c) {
		deleteStatement(sailStore.getValueFactory().createStatement(s, p, o, c));
	}

	public void deleteStatement(Resource s, IRI p, Value o) {
		deleteStatement(s, p, o, null);
	}

	private void ingestIncremental(String s, String p, String o, String c, boolean isDelete) {
		IngestEvent event = toIngestEvent(s, p, o, c, isDelete);
		if (event == null) {
			return;
		}
		IngestEvent[] batch = null;
		int batchSize = 0;
		synchronized (incrementalBufferLock) {
			ensureIncrementalBufferCapacity(incrementalBufferCount + 1);
			incrementalBuffer[incrementalBufferCount++] = event;
			if (incrementalBufferCount >= INCREMENTAL_BATCH_SIZE) {
				batch = drainIncrementalBufferLocked();
				batchSize = batch.length;
			}
		}
		if (batch != null) {
			applyIncrementalBatch(batch, batchSize);
		}
	}

	private IngestEvent toIngestEvent(String s, String p, String o, String c, boolean isDelete) {
		try {
			int si = hash(s);
			int pi = hash(p);
			int oi = hash(o);
			int ci = hash(c);

			long hs = valueFingerprint(s);
			long hp = valueFingerprint(p);
			long ho = valueFingerprint(o);
			long hc = valueFingerprint(c);
			long sig = quadFingerprint(hs, hp, ho, hc);
			long spKey = pairKey(si, pi);
			long soKey = pairKey(si, oi);
			long scKey = pairKey(si, ci);
			long poKey = pairKey(pi, oi);
			long pcKey = pairKey(pi, ci);
			long ocKey = pairKey(oi, ci);
			return new IngestEvent(isDelete, si, pi, oi, ci, hs, hp, ho, hc, sig, spKey, soKey, scKey, poKey, pcKey,
					ocKey);
		} catch (NullPointerException npe) {
			return null;
		}
	}

	private void ensureIncrementalBufferCapacity(int minCapacity) {
		if (minCapacity <= incrementalBuffer.length) {
			return;
		}
		int next = incrementalBuffer.length;
		while (next < minCapacity) {
			next <<= 1;
		}
		incrementalBuffer = Arrays.copyOf(incrementalBuffer, next);
	}

	private IngestEvent[] drainIncrementalBufferLocked() {
		if (incrementalBufferCount == 0) {
			return null;
		}
		IngestEvent[] drained = Arrays.copyOf(incrementalBuffer, incrementalBufferCount);
		Arrays.fill(incrementalBuffer, 0, incrementalBufferCount, null);
		incrementalBufferCount = 0;
		return drained;
	}

	private void flushPendingIncremental() {
		while (true) {
			IngestEvent[] batch;
			int batchSize;
			synchronized (incrementalBufferLock) {
				batch = drainIncrementalBufferLocked();
				if (batch == null) {
					return;
				}
				batchSize = batch.length;
			}
			applyIncrementalBatch(batch, batchSize);
		}
	}

	private void applyIncrementalBatch(IngestEvent[] batch, int batchSize) {
		if (batchSize == 0) {
			return;
		}

		while (true) {
			long epoch = rebuildEpoch.get();
			if ((epoch & 1L) != 0L) {
				synchronized (bufA) {
					ingestBatch(bufA, batch, batchSize);
				}
				synchronized (bufB) {
					ingestBatch(bufB, batch, batchSize);
				}
				return;
			}

			State target = current;
			synchronized (target) {
				if (rebuildEpoch.get() != epoch) {
					continue;
				}
				ingestBatch(target, batch, batchSize);
				return;
			}
		}
	}

	private void ingestBatch(State state, IngestEvent[] batch, int batchSize) {
		BatchUpdateAccumulator updates = new BatchUpdateAccumulator(Math.max(64, batchSize << 5));
		for (int i = 0; i < batchSize; i++) {
			IngestEvent event = batch[i];
			if (event == null) {
				continue;
			}
			accumulateIngestEvent(updates, event);
		}
		updates.forEach(
				(recType, isDelete, axisA, axisB, x, y, values, valueCount) -> applyGroupedUpdate(state, recType,
						isDelete, axisA, axisB, x, y, values, valueCount));
		enforceSketchBudget();
	}

	private void applyGroupedUpdate(State state, byte recType, boolean isDelete, byte axisA, byte axisB, int x, int y,
			long[] values, int valueCount) {
		int entryId;
		synchronized (sketchCacheLock) {
			entryId = cacheDirectory.findOrAdd(recType, isDelete, axisA, axisB, x, y);
		}
		SketchAddress address = new SketchAddress(recType, isDelete, axisA, axisB, x, y);
		UpdateSketch sketch = getSketchForWrite(state, address, entryId);
		for (int i = 0; i < valueCount; i++) {
			sketch.update(values[i]);
		}
		markDirty(state, entryId);
		touchResidentSketch(state, entryId, sketch, false);
	}

	private void accumulateIngestEvent(BatchUpdateAccumulator updates, IngestEvent event) {
		boolean isDelete = event.isDelete;
		int si = event.si;
		int pi = event.pi;
		int oi = event.oi;
		int ci = event.ci;
		long hs = event.hs;
		long hp = event.hp;
		long ho = event.ho;
		long hc = event.hc;
		long sig = event.sig;

		updates.add(REC_SINGLE_TRIPLE, isDelete, (byte) Component.S.ordinal(), (byte) 0, si, 0, sig);
		updates.add(REC_SINGLE_TRIPLE, isDelete, (byte) Component.P.ordinal(), (byte) 0, pi, 0, sig);
		updates.add(REC_SINGLE_TRIPLE, isDelete, (byte) Component.O.ordinal(), (byte) 0, oi, 0, sig);
		updates.add(REC_SINGLE_TRIPLE, isDelete, (byte) Component.C.ordinal(), (byte) 0, ci, 0, sig);

		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.S.ordinal(), (byte) Component.P.ordinal(), si, 0, hp);
		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.S.ordinal(), (byte) Component.O.ordinal(), si, 0, ho);
		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.S.ordinal(), (byte) Component.C.ordinal(), si, 0, hc);

		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.P.ordinal(), (byte) Component.S.ordinal(), pi, 0, hs);
		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.P.ordinal(), (byte) Component.O.ordinal(), pi, 0, ho);
		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.P.ordinal(), (byte) Component.C.ordinal(), pi, 0, hc);

		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.O.ordinal(), (byte) Component.S.ordinal(), oi, 0, hs);
		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.O.ordinal(), (byte) Component.P.ordinal(), oi, 0, hp);
		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.O.ordinal(), (byte) Component.C.ordinal(), oi, 0, hc);

		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.C.ordinal(), (byte) Component.S.ordinal(), ci, 0, hs);
		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.C.ordinal(), (byte) Component.P.ordinal(), ci, 0, hp);
		updates.add(REC_SINGLE_CPL, isDelete, (byte) Component.C.ordinal(), (byte) Component.O.ordinal(), ci, 0, ho);

		accumulatePair(updates, Pair.SP, isDelete, event.spKey, sig, ho, hc);
		accumulatePair(updates, Pair.SO, isDelete, event.soKey, sig, hp, hc);
		accumulatePair(updates, Pair.SC, isDelete, event.scKey, sig, hp, ho);
		accumulatePair(updates, Pair.PO, isDelete, event.poKey, sig, hs, hc);
		accumulatePair(updates, Pair.PC, isDelete, event.pcKey, sig, hs, ho);
		accumulatePair(updates, Pair.OC, isDelete, event.ocKey, sig, hs, hp);
	}

	private static void accumulatePair(BatchUpdateAccumulator updates, Pair pair, boolean isDelete, long key,
			long triple,
			long comp1, long comp2) {
		int x = (int) (key >>> 32);
		int y = (int) key;
		byte axis = (byte) pair.ordinal();
		updates.add(REC_PAIR_TRIPLE, isDelete, axis, (byte) 0, x, y, triple);
		updates.add(REC_PAIR_COMP1, isDelete, axis, (byte) 0, x, y, comp1);
		updates.add(REC_PAIR_COMP2, isDelete, axis, (byte) 0, x, y, comp2);
	}

	/* ------------------------------------------------------------------ */

	/**
	 * Common ingestion path for both add and delete operations.
	 *
	 * @param t        target {@code State} (one of the two buffers)
	 * @param st       statement to ingest
	 * @param isDelete {@code false}=live sketch, {@code true}=tomb‑stone sketch
	 */
	private void ingest(State t, Statement st, boolean isDelete) {
		try {
			String s = str(st.getSubject());
			String p = str(st.getPredicate());
			String o = str(st.getObject());
			String c = str(st.getContext());

			int si = hash(s), pi = hash(p), oi = hash(o), ci = hash(c);
			long hs = valueFingerprint(s);
			long hp = valueFingerprint(p);
			long ho = valueFingerprint(o);
			long hc = valueFingerprint(c);
			long sig = quadFingerprint(hs, hp, ho, hc);
			long spKey = pairKey(si, pi);
			long soKey = pairKey(si, oi);
			long scKey = pairKey(si, ci);
			long poKey = pairKey(pi, oi);
			long pcKey = pairKey(pi, ci);
			long ocKey = pairKey(oi, ci);

			/* single‑component cardinalities */
			updateSketch(t, singleTripleAddress(isDelete, Component.S, si), sig);
			updateSketch(t, singleTripleAddress(isDelete, Component.P, pi), sig);
			updateSketch(t, singleTripleAddress(isDelete, Component.O, oi), sig);
			updateSketch(t, singleTripleAddress(isDelete, Component.C, ci), sig);

			/* complement sets for singles */
			updateSketch(t, singleComplementAddress(isDelete, Component.S, Component.P, si), hp);
			updateSketch(t, singleComplementAddress(isDelete, Component.S, Component.O, si), ho);
			updateSketch(t, singleComplementAddress(isDelete, Component.S, Component.C, si), hc);

			updateSketch(t, singleComplementAddress(isDelete, Component.P, Component.S, pi), hs);
			updateSketch(t, singleComplementAddress(isDelete, Component.P, Component.O, pi), ho);
			updateSketch(t, singleComplementAddress(isDelete, Component.P, Component.C, pi), hc);

			updateSketch(t, singleComplementAddress(isDelete, Component.O, Component.S, oi), hs);
			updateSketch(t, singleComplementAddress(isDelete, Component.O, Component.P, oi), hp);
			updateSketch(t, singleComplementAddress(isDelete, Component.O, Component.C, oi), hc);

			updateSketch(t, singleComplementAddress(isDelete, Component.C, Component.S, ci), hs);
			updateSketch(t, singleComplementAddress(isDelete, Component.C, Component.P, ci), hp);
			updateSketch(t, singleComplementAddress(isDelete, Component.C, Component.O, ci), ho);

			/* pairs (triples + complements) */
			updatePairSketch(t, isDelete, Pair.SP, REC_PAIR_TRIPLE, spKey, sig);
			updatePairSketch(t, isDelete, Pair.SP, REC_PAIR_COMP1, spKey, ho);
			updatePairSketch(t, isDelete, Pair.SP, REC_PAIR_COMP2, spKey, hc);

			updatePairSketch(t, isDelete, Pair.SO, REC_PAIR_TRIPLE, soKey, sig);
			updatePairSketch(t, isDelete, Pair.SO, REC_PAIR_COMP1, soKey, hp);
			updatePairSketch(t, isDelete, Pair.SO, REC_PAIR_COMP2, soKey, hc);

			updatePairSketch(t, isDelete, Pair.SC, REC_PAIR_TRIPLE, scKey, sig);
			updatePairSketch(t, isDelete, Pair.SC, REC_PAIR_COMP1, scKey, hp);
			updatePairSketch(t, isDelete, Pair.SC, REC_PAIR_COMP2, scKey, ho);

			updatePairSketch(t, isDelete, Pair.PO, REC_PAIR_TRIPLE, poKey, sig);
			updatePairSketch(t, isDelete, Pair.PO, REC_PAIR_COMP1, poKey, hs);
			updatePairSketch(t, isDelete, Pair.PO, REC_PAIR_COMP2, poKey, hc);

			updatePairSketch(t, isDelete, Pair.PC, REC_PAIR_TRIPLE, pcKey, sig);
			updatePairSketch(t, isDelete, Pair.PC, REC_PAIR_COMP1, pcKey, hs);
			updatePairSketch(t, isDelete, Pair.PC, REC_PAIR_COMP2, pcKey, ho);

			updatePairSketch(t, isDelete, Pair.OC, REC_PAIR_TRIPLE, ocKey, sig);
			updatePairSketch(t, isDelete, Pair.OC, REC_PAIR_COMP1, ocKey, hs);
			updatePairSketch(t, isDelete, Pair.OC, REC_PAIR_COMP2, ocKey, hp);
		} catch (NullPointerException npe) {
			// ignore NPEs from null values (e.g. missing context)
		} finally {
			enforceSketchBudget();
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Quick cardinalities (public) */
	/* ────────────────────────────────────────────────────────────── */

	public double cardinalitySingle(Component c, String v) {
		flushPendingIncremental();
		State snap = current;
		synchronized (snap) {
			int idx = hash(v);
			UpdateSketch add = getSketchForRead(snap, singleTripleAddress(false, c, idx));
			UpdateSketch del = getSketchForRead(snap, singleTripleAddress(true, c, idx));
			return estimateMinus(add, del);
		}
	}

	public double cardinalityPair(Pair p, String x, String y) {
		flushPendingIncremental();
		State snap = current;
		synchronized (snap) {
			long key = pairKey(hash(x), hash(y));
			int row = (int) (key >>> 32);
			int col = (int) key;
			UpdateSketch add = getSketchForRead(snap, pairAddress(REC_PAIR_TRIPLE, false, p, row, col));
			UpdateSketch del = getSketchForRead(snap, pairAddress(REC_PAIR_TRIPLE, true, p, row, col));
			return estimateMinus(add, del);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Legacy join helpers (unchanged external API) */
	/* ────────────────────────────────────────────────────────────── */

	public double estimateJoinOn(Component join, Pair a, String ax, String ay,
			Pair b, String bx, String by) {
		State snap = current;
		synchronized (snap) {
			return joinPairs(snap, join, a, ax, ay, b, bx, by);
		}
	}

	public double estimateJoinOn(Component j, Component a, String av,
			Component b, String bv) {
		State snap = current;
		synchronized (snap) {
			return joinSingles(snap, j, a, av, b, bv);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* ✦ Fluent BGP builder ✦ */
	/* ────────────────────────────────────────────────────────────── */

	public JoinEstimate estimate(Component joinVar, String s, String p, String o, String c) {
		flushPendingIncremental();
		State snap = current;
		if (estimateCacheTtlNanos <= 0L) {
			synchronized (snap) {
				PatternStats st = statsOf(snap, joinVar, s, p, o, c);
				Sketch bindings = st.sketch == null ? EMPTY : st.sketch;
				return new JoinEstimate(snap, joinVar, bindings, bindings.getEstimate(), st.card);
			}
		}
		PatternStats st = patternStats(snap, joinVar, s, p, o, c);
		Sketch bindings = st.sketch == null ? EMPTY : st.sketch;
		return new JoinEstimate(snap, joinVar, bindings, bindings.getEstimate(), st.card);
	}

	public double estimateCount(Component joinVar, String s, String p, String o, String c) {
		return estimate(joinVar, s, p, o, c).estimate();
	}

	public final class JoinEstimate {
		private final State snap;
		private Component joinVar;
		private Sketch bindings;
		private double distinct;
		private double resultSize;

		private JoinEstimate(State snap, Component joinVar, Sketch bindings,
				double distinct, double size) {
			this.snap = snap;
			this.joinVar = joinVar;
			this.bindings = bindings;
			this.distinct = distinct;
			this.resultSize = size;
		}

		public JoinEstimate join(Component newJoinVar, String s, String p, String o, String c) {
			if (estimateCacheTtlNanos <= 0L) {
				synchronized (snap) {
					return joinWithPatternStats(newJoinVar, statsOf(snap, newJoinVar, s, p, o, c));
				}
			}
			return joinWithPatternStats(newJoinVar, patternStats(snap, newJoinVar, s, p, o, c));
		}

		private JoinEstimate joinWithPatternStats(Component newJoinVar, PatternStats rhs) {
			/* stats of the right‑hand relation */
			Intersection ix = SetOperation.builder().buildIntersection();
			ix.intersect(this.bindings);
			if (rhs.sketch != null) {
				ix.intersect(rhs.sketch);
			}
			Sketch inter = ix.getResult();
			double interDistinct = inter.getEstimate();

			if (interDistinct == 0.0) { // early out
				this.bindings = inter;
				this.distinct = 0.0;
				this.resultSize = 0.0;
				this.joinVar = newJoinVar;
				return this;
			}

			/* average fan‑outs */
			double leftAvg = Math.max(0.001, distinct == 0 ? 0 : resultSize / distinct);
			double rightAvg = Math.max(0.001, rhs.distinct == 0 ? 0 : rhs.card / rhs.distinct);

			/* join‑size estimate */
			double newSize = interDistinct * leftAvg * rightAvg;

			/* round to nearest whole solution count if enabled */
			this.resultSize = roundJoinEstimate(newSize);

			/* carry forward */
			this.bindings = inter;
			this.distinct = interDistinct;
			this.joinVar = newJoinVar;
			return this;
		}

		/** Estimated number of solutions produced so far. */
		public double estimate() {
			return resultSize;
		}

		public double size() {
			return resultSize;
		}

		public double count() {
			return resultSize;
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Pattern statistics */
	/* ────────────────────────────────────────────────────────────── */

	private static final class PatternStats {
		final Sketch sketch; // Θ‑sketch of join‑var bindings
		final double distinct; // = sketch.getEstimate()
		final double card; // relation size |R|

		PatternStats(Sketch s, double card) {
			this.sketch = s;
			this.distinct = s == null ? 0.0 : s.getEstimate();
			this.card = card;
		}
	}

	private static final class EstimateCacheKey {
		private final Component joinVar;
		private final String s;
		private final String p;
		private final String o;
		private final String c;

		private EstimateCacheKey(Component joinVar, String s, String p, String o, String c) {
			this.joinVar = Objects.requireNonNull(joinVar, "joinVar");
			this.s = s;
			this.p = p;
			this.o = o;
			this.c = c;
		}

		@Override
		public boolean equals(Object other) {
			if (this == other) {
				return true;
			}
			if (!(other instanceof EstimateCacheKey)) {
				return false;
			}
			EstimateCacheKey that = (EstimateCacheKey) other;
			return joinVar == that.joinVar
					&& Objects.equals(s, that.s)
					&& Objects.equals(p, that.p)
					&& Objects.equals(o, that.o)
					&& Objects.equals(c, that.c);
		}

		@Override
		public int hashCode() {
			return Objects.hash(joinVar, s, p, o, c);
		}
	}

	private static final class EstimateCacheEntry {
		private final PatternStats patternStats;
		private final long expiresAtNanos;

		private EstimateCacheEntry(PatternStats patternStats, long expiresAtNanos) {
			this.patternStats = Objects.requireNonNull(patternStats, "patternStats");
			this.expiresAtNanos = expiresAtNanos;
		}

		private boolean isAlive(long nowNanos) {
			return nowNanos - expiresAtNanos < 0L;
		}
	}

	private static final class BindingSketchResult {
		final Sketch sketch;
		final EnumSet<Pair> usedPairs;

		private BindingSketchResult(Sketch sketch, EnumSet<Pair> usedPairs) {
			this.sketch = sketch;
			this.usedPairs = usedPairs;
		}

		static BindingSketchResult of(Sketch sketch) {
			return new BindingSketchResult(sketch, EnumSet.noneOf(Pair.class));
		}

		static BindingSketchResult of(Sketch sketch, Pair pair) {
			return new BindingSketchResult(sketch, EnumSet.of(pair));
		}

		static BindingSketchResult of(Sketch sketch, Pair first, Pair second) {
			return new BindingSketchResult(sketch, EnumSet.of(first, second));
		}
	}

	private static final class PairSketchCandidate {
		final Pair pair;
		final Sketch sketch;

		PairSketchCandidate(Pair pair, Sketch sketch) {
			this.pair = pair;
			this.sketch = sketch;
		}
	}

	private static EnumMap<Component, String> fixedComponents(String s, String p, String o, String c) {
		EnumMap<Component, String> fixed = new EnumMap<>(Component.class);
		if (s != null) {
			fixed.put(Component.S, s);
		}
		if (p != null) {
			fixed.put(Component.P, p);
		}
		if (o != null) {
			fixed.put(Component.O, o);
		}
		if (c != null) {
			fixed.put(Component.C, c);
		}
		return fixed;
	}

	/** Build both |R| and Θ‑sketch for one triple pattern. */
	private PatternStats statsOf(State st, Component j,
			String s, String p, String o, String c) {

		EnumMap<Component, String> fixed = fixedComponents(s, p, o, c);
		BindingSketchResult bindingSketch = bindingsSketch(st, j, fixed);
		Sketch sk = bindingSketch.sketch;

		double pairDrivenCardinality = usedPairCardinality(st, fixed, bindingSketch.usedPairs);
		if (Double.isFinite(pairDrivenCardinality)) {
			return new PatternStats(sk, enforceCardinalityLowerBound(sk, pairDrivenCardinality));
		}

		double card;

		switch (fixed.size()) {
		case 0:
			card = approxTotalRows();
			break;

		case 1: {
			Map.Entry<Component, String> e = fixed.entrySet().iterator().next();
			card = cardSingle(st, e.getKey(), e.getValue());
			break;
		}

		case 2: {
			Component[] cmp = fixed.keySet().toArray(new Component[0]);
			Pair pr = findPair(cmp[0], cmp[1]);
			if (pr != null) {
				card = cardPair(st, pr, fixed.get(pr.x), fixed.get(pr.y));
			} else { // components not a known pair – conservative min
				double a = cardSingle(st, cmp[0], fixed.get(cmp[0]));
				double b = cardSingle(st, cmp[1], fixed.get(cmp[1]));
				card = Math.min(a, b);
			}
			break;
		}

		default: { // 3 or 4 bound – use smallest single cardinality
			card = Double.POSITIVE_INFINITY;
			for (Map.Entry<Component, String> e : fixed.entrySet()) {
				card = Math.min(card, cardSingle(st, e.getKey(), e.getValue()));
			}
			break;
		}
		}
		return new PatternStats(sk, enforceCardinalityLowerBound(sk, card));
	}

	private PatternStats patternStats(State snap, Component joinVar, String s, String p, String o, String c) {
		if (estimateCacheTtlNanos <= 0L) {
			synchronized (snap) {
				return statsOf(snap, joinVar, s, p, o, c);
			}
		}

		long nowNanos = System.nanoTime();
		EstimateCacheKey key = new EstimateCacheKey(joinVar, s, p, o, c);
		EstimateCacheEntry cached = estimateCache.get(key);
		if (cached != null && cached.isAlive(nowNanos)) {
			return cached.patternStats;
		}

		PatternStats frozenStats;
		synchronized (snap) {
			frozenStats = freezePatternStats(statsOf(snap, joinVar, s, p, o, c));
		}
		estimateCache.put(key, new EstimateCacheEntry(frozenStats, saturatingAdd(nowNanos, estimateCacheTtlNanos)));
		trimEstimateCache(nowNanos);
		return frozenStats;
	}

	private PatternStats freezePatternStats(PatternStats patternStats) {
		if (patternStats.sketch == null) {
			return patternStats;
		}
		return new PatternStats(patternStats.sketch.compact(), patternStats.card);
	}

	private void trimEstimateCache(long nowNanos) {
		if (estimateCache.size() <= MAX_ESTIMATE_CACHE_ENTRIES) {
			return;
		}
		for (Map.Entry<EstimateCacheKey, EstimateCacheEntry> entry : estimateCache.entrySet()) {
			if (!entry.getValue().isAlive(nowNanos)) {
				estimateCache.remove(entry.getKey(), entry.getValue());
			}
		}
		if (estimateCache.size() > MAX_ESTIMATE_CACHE_ENTRIES) {
			estimateCache.clear();
		}
	}

	private void clearEstimateCache() {
		estimateCache.clear();
	}

	private double approxTotalRows() {
		return Math.max(0.0d, (double) Math.max(seenTriples, approxStoreSize.get()));
	}

	private double usedPairCardinality(State st, EnumMap<Component, String> fixed, EnumSet<Pair> usedPairs) {
		if (usedPairs.isEmpty()) {
			return Double.NaN;
		}
		double card = Double.POSITIVE_INFINITY;
		for (Pair pair : usedPairs) {
			String xValue = fixed.get(pair.x);
			String yValue = fixed.get(pair.y);
			if (xValue == null || yValue == null) {
				continue;
			}
			card = Math.min(card, cardPair(st, pair, xValue, yValue));
		}
		return Double.isFinite(card) ? card : Double.NaN;
	}

	private static double enforceCardinalityLowerBound(Sketch sketch, double cardinality) {
		if (sketch == null || !Double.isFinite(cardinality)) {
			return cardinality;
		}
//		if(cardinality < sketch.getEstimate()){
//			System.out.println("Cardinality " + cardinality + " is lower than sketch estimate " + sketch.getEstimate());
//		}else if(cardinality > sketch.getEstimate()) {
//			System.out.println("Cardinality " + cardinality + " is higher than sketch estimate " + sketch.getEstimate());
//		}

		// Cardinality cannot be lower than the estimated number of distinct join bindings.
//		return Math.max(cardinality, sketch.getEstimate());
		return cardinality;
	}

