	private static double estimateMinus(UpdateSketch add, UpdateSketch del) {
		if (add == null) {
			return 0.0;
		}
		if (del == null || del.getRetainedEntries() == 0) {
			return add.getEstimate();
		}
		AnotB diff = SetOperation.builder().buildANotB();
		diff.setA(add);
		diff.notB(del);
		return diff.getResult(false).getEstimate();
	}

	private static Sketch subtractSketch(UpdateSketch add, UpdateSketch del) {
		if (add == null) {
			return null;
		}
		if (del == null || del.getRetainedEntries() == 0) {
			return add;
		}
		AnotB diff = SetOperation.builder().buildANotB();
		diff.setA(add);
		diff.notB(del);
		return diff.getResult(false);
	}

	private static UpdateSketch newSk(int k) {
		return UpdateSketch.builder()
				.setFamily(Family.ALPHA)
				.setResizeFactor(ResizeFactor.X8)
				.setNominalEntries(k)
				.build();
	}

	private static Method resolveHashUpdateMethod() {
		try {
			Method method = UpdateSketch.class.getDeclaredMethod("hashUpdate", long.class);
			method.setAccessible(true);
			return method;
		} catch (NoSuchMethodException e) {
			throw new ExceptionInInitializerError(e);
		}
	}

	private static Method resolveAccessibleMethod(Class<?> owner, String methodName, Class<?>... parameterTypes) {
		try {
			Method method = owner.getDeclaredMethod(methodName, parameterTypes);
			method.setAccessible(true);
			return method;
		} catch (NoSuchMethodException e) {
			throw new ExceptionInInitializerError(e);
		}
	}

	private static Field resolveHeapAlphaField(String fieldName) {
		try {
			Class<?> heapAlphaClass = Class.forName("org.apache.datasketches.theta.HeapAlphaSketch");
			Field field = heapAlphaClass.getDeclaredField(fieldName);
			field.setAccessible(true);
			return field;
		} catch (ClassNotFoundException | NoSuchFieldException e) {
			throw new ExceptionInInitializerError(e);
		}
	}

	private static void hashUpdateRaw(UpdateSketch sketch, long hash) throws IOException {
		try {
			HASH_UPDATE_METHOD.invoke(sketch, hash);
		} catch (IllegalAccessException e) {
			throw new IOException("Unable to apply raw sketch hash", e);
		} catch (InvocationTargetException e) {
			Throwable cause = e.getCause();
			if (cause instanceof RuntimeException) {
				throw (RuntimeException) cause;
			}
			if (cause instanceof Error) {
				throw (Error) cause;
			}
			throw new IOException("Unable to apply raw sketch hash", cause);
		}
	}

	private static long invokeLongMethod(Method method, Object target) {
		try {
			Object value = method.invoke(target);
			if (!(value instanceof Number number)) {
				throw new IllegalStateException("Expected numeric result from " + method);
			}
			return Math.max(0L, number.longValue());
		} catch (IllegalAccessException e) {
			throw new IllegalStateException("Unable to invoke " + method, e);
		} catch (InvocationTargetException e) {
			Throwable cause = e.getCause();
			if (cause instanceof RuntimeException runtimeException) {
				throw runtimeException;
			}
			if (cause instanceof Error error) {
				throw error;
			}
			throw new IllegalStateException("Unable to invoke " + method, cause);
		}
	}

	private static void invokeVoidMethod(Method method, Object target, Object... args) {
		try {
			method.invoke(target, args);
		} catch (IllegalAccessException e) {
			throw new IllegalStateException("Unable to invoke " + method, e);
		} catch (InvocationTargetException e) {
			Throwable cause = e.getCause();
			if (cause instanceof RuntimeException runtimeException) {
				throw runtimeException;
			}
			if (cause instanceof Error error) {
				throw error;
			}
			throw new IllegalStateException("Unable to invoke " + method, cause);
		}
	}

	private static Object invokeObjectMethod(Method method, Object target, Object... args) {
		try {
			return method.invoke(target, args);
		} catch (IllegalAccessException e) {
			throw new IllegalStateException("Unable to invoke " + method, e);
		} catch (InvocationTargetException e) {
			Throwable cause = e.getCause();
			if (cause instanceof RuntimeException runtimeException) {
				throw runtimeException;
			}
			if (cause instanceof Error error) {
				throw error;
			}
			throw new IllegalStateException("Unable to invoke " + method, cause);
		}
	}

	private static long align(long bytes) {
		return (bytes + 7L) & ~7L;
	}

	private static void applySerializedThetaAndEmpty(UpdateSketch sketch, long thetaLong, boolean empty)
			throws IOException {
		try {
			HEAP_ALPHA_THETA_LONG_FIELD.setLong(sketch, thetaLong);
			HEAP_ALPHA_EMPTY_FIELD.setBoolean(sketch, empty);
		} catch (IllegalAccessException | IllegalArgumentException e) {
			throw new IOException("Unable to restore sketch theta metadata", e);
		}
	}

	private int hash(String v) {
		// Ensure non-negative index in [0, nominalEntries)
		int h = Objects.hashCode(v);
		return (h & 0x7fffffff) % nominalEntries;
	}

	private static long valueFingerprint(String value) {
		long h = FNV64_OFFSET_BASIS;
		if (value != null) {
			for (int i = 0; i < value.length(); i++) {
				h ^= value.charAt(i);
				h *= FNV64_PRIME;
			}
			h ^= value.length();
		}
		return mix64(h);
	}

	private static long quadFingerprint(long s, long p, long o, long c) {
		long h = QUAD_SEED;
		h = mix64(h ^ s);
		h = mix64(h ^ p);
		h = mix64(h ^ o);
		return mix64(h ^ c);
	}

	private static long mix64(long value) {
		long z = value;
		z = (z ^ (z >>> 30)) * MIX64_C1;
		z = (z ^ (z >>> 27)) * MIX64_C2;
		return z ^ (z >>> 31);
	}

	private static long pairKey(int a, int b) {
		return (((long) a) << 32) ^ (b & 0xffffffffL);
	}

	private static Pair findPair(Component a, Component b) {
		for (Pair p : Pair.values()) {
			if ((p.x == a && p.y == b) || (p.x == b && p.y == a)) {
				return p;
			}
		}
		return null;
	}

	private String str(Resource r) {
		return r == null ? defaultContextString : r.stringValue();
	}

	private String str(Value v) {
		return v == null ? defaultContextString : v.stringValue();
	}

	private static String sig(String s, String p, String o, String c) {
		return s + ' ' + p + ' ' + o + ' ' + c;
	}

